class ReleaseStore {
  final Map<String, Map<String, String>> _releases = {};

  void add(String releaseId, Map<String, String> files) {
    _releases[releaseId] = Map<String, String>.unmodifiable(files);
  }

  bool contains(String releaseId) => _releases.containsKey(releaseId);

  Map<String, String> snapshot(String releaseId) {
    final files = _releases[releaseId];
    if (files == null) throw StateError('Unknown release: $releaseId');
    return files;
  }

  void delete(String releaseId) {
    _releases.remove(releaseId);
  }
}

