class ReleaseHandle {
  ReleaseHandle(this.releaseId, Map<String, String> files) : _files = files;

  final String releaseId;
  final Map<String, String> _files;
  bool _closed = false;

  bool get isClosed => _closed;

  String read(String path) {
    if (_closed) throw StateError('Release handle is closed');
    final value = _files[path];
    if (value == null) throw StateError('Missing release file: $path');
    return value;
  }

  void close() {
    if (_closed) throw StateError('Release handle is already closed');
    _closed = true;
  }
}

