import 'release_handle.dart';
import 'release_store.dart';

class ReleaseManager {
  ReleaseManager(this.store);

  final ReleaseStore store;
  String? _activeRelease;

  String? get activeRelease => _activeRelease;

  void activate(String releaseId) {
    if (!store.contains(releaseId)) {
      throw StateError('Cannot activate an unknown release');
    }
    final previous = _activeRelease;
    _activeRelease = releaseId;
    if (previous != null && previous != releaseId) {
      store.delete(previous);
    }
  }

  ReleaseHandle openActive() {
    final releaseId = _activeRelease;
    if (releaseId == null) throw StateError('No active release');
    return ReleaseHandle(releaseId, store.snapshot(releaseId));
  }
}

