import '../lib/release_manager.dart';
import '../lib/release_store.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

void main() {
  final store = ReleaseStore()
    ..add('blue', {'index.html': 'blue page'});
  final manager = ReleaseManager(store)..activate('blue');
  final handle = manager.openActive();
  check(handle.releaseId == 'blue', 'the active release is opened');
  check(handle.read('index.html') == 'blue page', 'release contents are readable');
  handle.close();
  check(handle.isClosed, 'a handle closes');

  store.add('green', {'index.html': 'green page'});
  manager.activate('green');
  check(manager.activeRelease == 'green', 'activation switches the release');
  check(!store.contains('blue'), 'an unused retired release is removed');
  final current = manager.openActive();
  check(current.read('index.html') == 'green page', 'the new release is served');
  current.close();
}
